    if buf[:3] in (b"v10", b"v20"):
        try:
            from Cryptodome.Cipher import AES
        except ImportError:
            from Crypto.Cipher import AES
        iv, payload = buf[3:15], buf[15:]
        cipher = AES.new(key, AES.MODE_GCM, iv)
        return cipher.decrypt(payload)[:-16].decode("utf-8", "replace")
    import ctypes
